#!/usr/bin/env python3
"""cfgpipe - A command-line configuration resolver with watch mode and change events."""

import json
import os
import sys
import time
import urllib.parse
import urllib.request
import urllib.error
from typing import Any, Iterator


def compose_path(parent: str, key: str) -> str:
    """Compose a dot-separated path from parent and key."""
    return f"{parent}.{key}" if parent else key


def parse_cli_args(args: list[str]) -> tuple[dict[str, str], list[str]]:
    """Parse CLI arguments in --name=value format.

    Returns (parsed_args, unparsed_args) where parsed_args is a dict of
    name -> value pairs for arguments that match --name=value pattern.
    """
    parsed: dict[str, str] = {}
    unparsed: list[str] = []
    for arg in args:
        if arg.startswith('--') and '=' in arg:
            name, value = arg[2:].split('=', 1)
            parsed[name] = value
        else:
            unparsed.append(arg)
    return parsed, unparsed


def get_env_value(env_name: str) -> str | None:
    return os.environ.get(env_name, "").strip() or None


def get_file_value(file_path: str) -> str | None:
    """Return file content if it exists as a regular file with non-empty content."""
    try:
        if not os.path.isfile(file_path):
            return None
        return open(file_path).read().strip() or None
    except (OSError, IOError):
        return None


def validate_schema_recursive(
    schema: dict[str, Any],
    current_path: str,
    errors: list[str],
    primary_store_map: dict[str, list[str]],
    secondary_store_map: dict[str, list[str]]
) -> None:
    """Recursively validate schema structure.

    Collects all schema errors and tracks primary-store and secondary-store key usage.
    """
    if not isinstance(schema, dict):
        errors.append(f"{current_path}: schema root must be a JSON object")
        return

    if not schema:
        if current_path == "":
            errors.append("schema root must be non-empty")
        return

    seen_keys = set()

    for key, value in schema.items():
        # Check for duplicate keys within same group
        path = f"{current_path}.{key}" if current_path else key
        if key in seen_keys:
            errors.append(f"{path}: duplicate parameter/group name")
        seen_keys.add(key)

        if isinstance(value, dict):
            # Check if this is a parameter declaration or a group
            has_type = 'type' in value

            if has_type:
                # This is a parameter declaration
                type_val = value['type']

                # Check type is recognized
                if not is_valid_type(type_val):
                    errors.append(f"{path}: unrecognized type '{type_val}'")

                # Check source-annotation keys are strings
                for field in ['default', 'env', 'file', 'arg']:
                    if field in value and not isinstance(value[field], str):
                        errors.append(f"{path}: '{field}' field must be a string")

                # Track primary-store keys across full hierarchy
                if 'primary-store' in value:
                    if not isinstance(value['primary-store'], str):
                        errors.append(f"{path}: 'primary-store' field must be a string")
                    else:
                        pstore_key = value['primary-store']
                        if pstore_key not in primary_store_map:
                            primary_store_map[pstore_key] = []
                        primary_store_map[pstore_key].append(path)

                # Track secondary-store keys across full hierarchy
                if 'secondary-store' in value:
                    if not isinstance(value['secondary-store'], str):
                        errors.append(f"{path}: 'secondary-store' field must be a string")
                    else:
                        sstore_key = value['secondary-store']
                        if sstore_key not in secondary_store_map:
                            secondary_store_map[sstore_key] = []
                        secondary_store_map[sstore_key].append(path)
            else:
                # This is a group - must not have source-annotation keys with non-object values
                for field in ['default', 'env', 'file', 'arg', 'primary-store', 'secondary-store']:
                    if field in value:
                        errors.append(f"{path}: group carries source annotation '{field}'")
                # Recursively validate the group contents
                validate_schema_recursive(value, path, errors, primary_store_map, secondary_store_map)
        else:
            # Value is not an object - invalid
            errors.append(f"{path}: must be an object (parameter declaration or group)")


