def _get_param_type(node: dict[str, Any], path: str) -> str | None:
    """Get the type of a parameter at the given path from the original schema."""
    parts = path.split('.')
    current = node
    for part in parts:
        if part in current and isinstance(current[part], dict) and 'type' in current[part]:
            current = current[part]
        elif part in current and isinstance(current[part], dict):
            current = current[part]
        else:
            return None
    if isinstance(current, dict) and 'type' in current:
        return current['type']
    return None


def check_secondary_store_config(
    schema: dict[str, Any],
    secondary_store_url: str | None,
    watch_mode: bool,
    poll_interval: float | None,
) -> str | None:
    """Validate secondary-store configuration.

    In watch mode with --secondary-store, requires at least one parameter
    declaring secondary-store, and poll_interval must be strictly positive.
    """
    if not watch_mode:
        return None

    if secondary_store_url is None:
        return None  # Not an error if no secondary-store specified

    if poll_interval is not None and poll_interval <= 0:
        return "Error: --secondary-store-poll-interval must be strictly positive"

    # Check that at least one parameter declares secondary-store
    def has_secondary_store(node: dict[str, Any]) -> bool:
        for key, value in node.items():
            if isinstance(value, dict) and 'type' in value:
                if 'secondary-store' in value:
                    return True
            elif isinstance(value, dict):
                if has_secondary_store(value):
                    return True
        return False

    if not has_secondary_store(schema):
        return "Error: no parameters declare secondary-store but --secondary-store is specified"

    return None


def parse_duration(duration_str: str) -> float | None:
    """Parse a duration string like '2s' and return seconds as float.

    Returns None if the format is invalid.
    """
    duration_str = duration_str.strip()
    if duration_str.endswith('s'):
        try:
            return float(duration_str[:-1])
        except ValueError:
            return None
    return None


def emit_change_event(path: str, type_name: str, previous: str, current: str) -> None:
    """Emit a single change event JSON line to stdout."""
    event = {
        'path': path,
        'type': type_name,
        'previous': previous,
        'current': current
    }
    print(json.dumps(event))


def collect_primary_store_params(schema: dict[str, Any]) -> dict[str, str]:
    """Collect all parameters that have primary-store annotation.

    Returns a dict mapping path -> primary-store key.
    """
    result: dict[str, str] = {}

    def collect(node: dict[str, Any], current_path: str) -> None:
        for key, value in node.items():
            path = compose_path(current_path, key) if current_path else key
            if isinstance(value, dict) and 'type' in value:
                if 'primary-store' in value:
                    result[path] = value['primary-store']
            elif isinstance(value, dict):
                collect(value, path)

    collect(schema, "")
    return result


def collect_secondary_store_params(schema: dict[str, Any]) -> dict[str, str]:
    """Collect all parameters that have secondary-store annotation.

    Returns a dict mapping path -> secondary-store key.
    """
    result: dict[str, str] = {}

    def collect(node: dict[str, Any], current_path: str) -> None:
        for key, value in node.items():
            path = compose_path(current_path, key) if current_path else key
            if isinstance(value, dict) and 'type' in value:
                if 'secondary-store' in value:
                    result[path] = value['secondary-store']
            elif isinstance(value, dict):
                collect(value, path)

