                    if not isinstance(value['secondary-store'], str):
                        errors.append(f"{path}: 'secondary-store' field must be a string")
                    else:
                        sstore_key = value['secondary-store']
                        if sstore_key not in secondary_store_map:
                            secondary_store_map[sstore_key] = []
